// Format Website Contact Form submission for Airtable.
// Includes server-side validation: strips placeholder echoes, flags suspicious leads.
const raw = $input.first().json;
const d = raw.body || raw;
const now = new Date().toISOString();
const id = 'WEB-' + Math.random().toString(36).substring(2,10).toUpperCase();
const sourceMap = {'google':'Paid','meta':'Paid','facebook':'Paid','tiktok':'Paid','linkedin':'Social_LinkedIn','twitter':'Social_Twitter','instagram':'Social_IG'};
const utmSrc = (d.utm_source || '').toLowerCase();
const sourceChannel = sourceMap[utmSrc] || (utmSrc === 'organic' ? 'Organic' : 'Direct');

// --- Server-side validation guard ---
const PLACEHOLDERS = {
  company: ['your company name', 'acme corp', 'company name'],
  contactName: ['your full name', 'jane smith', 'your name', 'first name last name'],
  email: ['you@company.com', 'jane@company.com', 'name@example.com'],
  message: [
    "what's the most repetitive task you wish you could automate?",
    'what is the most repetitive task you wish you could automate?',
    'briefly describe what you are looking to achieve with ai...'
  ]
};
const flags = [];
function sanitize(val, fieldKey) {
  if (!val) return '';
  const clean = String(val).trim();
  const lower = clean.toLowerCase();
  const placeholders = PLACEHOLDERS[fieldKey] || [];
  for (let i = 0; i < placeholders.length; i++) {
    if (lower === placeholders[i]) {
      flags.push(fieldKey + '=placeholder-echo');
      return '';
    }
  }
  if (fieldKey === 'message' && /^what(?:'?s|\s+is)?\s+the\s+(?:most|msot)\b/i.test(clean)) {
    flags.push('message=question-echo');
    return '';
  }
  return clean;
}

const rawCompany = sanitize(d.company, 'company');
const rawEmail = sanitize(d.email, 'email');
const rawMessage = sanitize(d.message, 'message');
const rawContactName = sanitize(
  ((d.firstName||'') + ' ' + (d.lastName||'')).trim() || d.name || '',
  'contactName'
);

if (rawCompany && rawCompany.length < 2) flags.push('company=too-short');
if (rawContactName && rawContactName.length < 2) flags.push('name=too-short');
if (rawMessage && rawMessage.length > 0 && rawMessage.length < 10) flags.push('message=too-short');
if (rawEmail && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(rawEmail)) flags.push('email=malformed');

let grade = 'Warm';
if (flags.length >= 2) grade = 'Cold';

let notes = rawMessage || '';
if (flags.length > 0) {
  notes = (notes ? notes + ' | ' : '') + '[FLAGGED: ' + flags.join(', ') + ']';
}

return [{json: {
  'Lead ID': id,
  'Contact Name': rawContactName || 'Unknown',
  'Email': rawEmail,
  'Phone': sanitize(d.phone, 'phone') || '',
  'Company': rawCompany,
  'Source Channel': sourceChannel,
  'Source URL': d.page_url || '',
  'UTM Campaign': d.utm_campaign || '',
  'UTM Medium': d.utm_medium || '',
  'UTM Source': d.utm_source || '',
  'First Touch Content': d.interest || '',
  'Status': 'New',
  'Source System': 'SEO_Inbound',
  'Grade': grade,
  'Notes': notes,
  'Created At': now.split('T')[0],
}}];
